import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbDistinctCursorSkipContextTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void distinctPredicateGraphScopeUsesCursorSkipAcrossContexts(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			Set<IRI> expectedPredicates = new LinkedHashSet<>();
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				for (int predicateIndex = 0; predicateIndex < 4; predicateIndex++) {
					IRI predicate = VF.createIRI("urn:distinct:graph:p:" + predicateIndex);
					expectedPredicates.add(predicate);
					for (int graphIndex = 0; graphIndex < 3; graphIndex++) {
						IRI graph = VF.createIRI("urn:distinct:graph:g:" + graphIndex);
						for (int row = 0; row < 20; row++) {
							connection.add(VF.createIRI("urn:distinct:graph:s:" + predicateIndex + ":" + row),
									predicate, VF.createIRI("urn:distinct:graph:o:" + graphIndex + ":" + row),
									graph);
						}
					}
				}
				connection.commit();
				store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
				LmdbPlannerAwait.awaitSketchesReady(store);

				String query = "SELECT DISTINCT ?p WHERE { GRAPH ?g { ?s ?p ?o } }";
				Set<Value> resultPredicates = new LinkedHashSet<>();
				try (TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
					while (result.hasNext()) {
						resultPredicates.add(result.next().getValue("p"));
					}
				}
				assertEquals(expectedPredicates, resultPredicates);

				Explanation explanation = explain(connection, query);
				StatementPattern pattern = firstStatementPattern((TupleExpr) explanation.tupleExpr());
				assertNotNull(pattern, explanation::toString);
				assertUsesCursorSkip(pattern, explanation);
				assertEquals(expectedPredicates.size(), pattern.getSourceRowsMatchedActual(), explanation::toString);
				assertTrue(pattern.getSourceRowsScannedActual() <= expectedPredicates.size() + 2L,
						"GRAPH DISTINCT should skip context/object/subject suffixes and scan near predicate count:\n"
								+ explanation);
			}
		} finally {
			shutDownAndDelete(repository, dataDir);
		}
	}
}
